// Geometry Studio - advanced capstone reference solution.
#include <cmath>
#include <iomanip>
#include <iostream>
#include <memory>
#include <sstream>
#include <stdexcept>
#include <string>
#include <vector>

class ShapeError : public std::runtime_error {
public:
    explicit ShapeError(const std::string& m) : std::runtime_error(m) {}
};

class Shape {
public:
    virtual ~Shape() = default;
    virtual std::string name() const = 0;
    virtual double area() const = 0;
    virtual double perimeter() const = 0;
};

class Circle final : public Shape {
    double r_;
public:
    explicit Circle(double r) : r_(r) {
        if (r_ <= 0) throw ShapeError("circle radius must be positive");
    }
    std::string name() const override { return "circle"; }
    double area() const override { return 3.14159265358979323846 * r_ * r_; }
    double perimeter() const override { return 2 * 3.14159265358979323846 * r_; }
};

class Rectangle final : public Shape {
    double w_, h_;
public:
    Rectangle(double w, double h) : w_(w), h_(h) {
        if (w_ <= 0 || h_ <= 0) throw ShapeError("rectangle sides must be positive");
    }
    std::string name() const override { return "rectangle"; }
    double area() const override { return w_ * h_; }
    double perimeter() const override { return 2 * (w_ + h_); }
};

class Triangle final : public Shape {
    double a_, b_, c_;
public:
    Triangle(double a, double b, double c) : a_(a), b_(b), c_(c) {
        if (a_ <= 0 || b_ <= 0 || c_ <= 0)
            throw ShapeError("triangle sides must be positive");
        if (a_ + b_ <= c_ || a_ + c_ <= b_ || b_ + c_ <= a_)
            throw ShapeError("triangle inequality violated");
    }
    std::string name() const override { return "triangle"; }
    double area() const override {
        double s = (a_ + b_ + c_) / 2.0;
        return std::sqrt(s * (s - a_) * (s - b_) * (s - c_));
    }
    double perimeter() const override { return a_ + b_ + c_; }
};

template <typename T>
class Stats {
    std::vector<T> xs_;
public:
    void add(T v) { xs_.push_back(v); }
    std::size_t count() const { return xs_.size(); }
    T min() const {
        T m = xs_.front();
        for (const T& v : xs_) if (v < m) m = v;
        return m;
    }
    T max() const {
        T m = xs_.front();
        for (const T& v : xs_) if (v > m) m = v;
        return m;
    }
    T avg() const {
        T s = T{};
        for (const T& v : xs_) s = s + v;
        return s / static_cast<T>(xs_.size());
    }
};

static std::unique_ptr<Shape> parseShape(const std::string& line) {
    std::istringstream iss(line);
    std::string kind;
    iss >> kind;
    if (kind == "circle") {
        double r;
        if (!(iss >> r)) throw ShapeError("expected radius");
        return std::make_unique<Circle>(r);
    }
    if (kind == "rectangle") {
        double w, h;
        if (!(iss >> w >> h)) throw ShapeError("expected width and height");
        return std::make_unique<Rectangle>(w, h);
    }
    if (kind == "triangle") {
        double a, b, c;
        if (!(iss >> a >> b >> c)) throw ShapeError("expected three sides");
        return std::make_unique<Triangle>(a, b, c);
    }
    throw ShapeError("unknown shape: " + kind);
}

int main() {
    std::vector<std::unique_ptr<Shape>> shapes;
    std::string line;
    std::cout << std::fixed << std::setprecision(2);
    while (std::getline(std::cin, line)) {
        if (line.empty()) continue;
        std::istringstream peek(line);
        std::string cmd;
        peek >> cmd;
        try {
            if (cmd == "quit") break;
            if (cmd == "list") {
                for (std::size_t i = 0; i < shapes.size(); ++i) {
                    std::cout << i << " " << shapes[i]->name()
                              << " area=" << shapes[i]->area()
                              << " perimeter=" << shapes[i]->perimeter() << "\n";
                }
            } else if (cmd == "summary") {
                double total = 0;
                for (const auto& s : shapes) total += s->area();
                std::cout << "count=" << shapes.size() << " total_area=" << total << "\n";
            } else if (cmd == "stats") {
                if (shapes.empty()) { std::cout << "no shapes\n"; continue; }
                Stats<double> a, p;
                for (const auto& s : shapes) { a.add(s->area()); p.add(s->perimeter()); }
                std::cout << "area min=" << a.min() << " max=" << a.max() << " avg=" << a.avg() << "\n";
                std::cout << "perimeter min=" << p.min() << " max=" << p.max() << " avg=" << p.avg() << "\n";
            } else {
                auto shape = parseShape(line);
                std::cout << "added " << shape->name() << " area=" << shape->area()
                          << " perimeter=" << shape->perimeter() << "\n";
                shapes.push_back(std::move(shape));
            }
        } catch (const ShapeError& e) {
            std::cout << "ERROR: " << e.what() << "\n";
        }
    }
    return 0;
}
